class Solution {
    public int numberOfWays(int n, int x) {
        long mod = 1000000007;
        int count = 0;
        for (int i = 1; i * x <= n; i++) {
            long power = 1;
            for (int j = 0; j < x; j++) {
                power = (power * i) % mod;
            }
            if (power == n) {
                count++;
            }
        }
        return count;
    }
}
